CREATE VIEW `ads_ads_fbs2s_sender_view` (`dt` COMMENT "日期，根据CreateTime创建", `Id` COMMENT "自增id", `create_time` COMMENT "创建时间", `user_id` COMMENT "用户id", `pixel_id` COMMENT "像素id", `Data` COMMENT "发送的json格式数据", `Status` COMMENT "状态0未发送,1发送成功,其他异常", `finish_time` COMMENT "完成时间", `event_type` COMMENT "事件类型", `desc_info` COMMENT "发送结果", `order_serial_id` COMMENT "订单序列号,充值事件有值", `event_time` COMMENT "事件时间", `page_view_time` COMMENT "页面时间", `ad_id` COMMENT "广告Id", `trace_id` COMMENT "追踪Id,和 Notify表数据关联", `c2rtime` COMMENT "用户点击continue to read 按钮的时间，相当于点击跳到商店页的按钮")
